const html = $input.first().json.data;
const baseUrl = $('Edit Fields').first().json.URL;
const regex = /href="([^"]+)"/g;
const results = [];
let match;

while ((match = regex.exec(html)) !== null) {
  const link = match[1];
  if (link.includes('/product')) {
    results.push(baseUrl + link);
  }
}

if (results.length === 0) {
  return [
    {
      json: {
        urls: null,
        message: "false"
      }
    }
  ];
}

return [
  {
    json: {
      message: "true",
      urls: results.join('\n')
    }
  }
];

const output = $input.first().json.output || "";

// Normalize text
const text = output.trim();

// Required sections in strict order
const sections = [
  "--Overview--",
  "--compatibility_check--",
  "--titles_audit--",
  "--photos_audit--",
  "--descriptions_audit--",
  "--categories_audit--",
  "--product_names_audit--",
  "--recommanded_fixes--",
  "--final_assessment--"
];

// Initialize
let isValid = true;
let issues = [];



// Rule 2: No intro or extra text before first section
if (!text.startsWith("--Overview--")) {
  isValid = false;
  issues.push("CRITICAL: Output does not start with --Overview--.");
}

// Rule 3: Check all sections exist and in order
let lastIndex = -1;
sections.forEach((section) => {
  const index = text.indexOf(section);
  if (index === -1) {
    isValid = false;
    issues.push(`CRITICAL: Missing section ${section}.`);
  } else if (index < lastIndex) {
    isValid = false;
    issues.push(`CRITICAL: Section ${section} is out of order.`);
  }
  lastIndex = index;
});

// Rule 4: Ensure ONLY these sections exist
const extraSectionPattern = /--[a-zA-Z_]+--/g;
const foundSections = text.match(extraSectionPattern) || [];

foundSections.forEach(sec => {
  if (!sections.includes(sec)) {
    isValid = false;
    issues.push(`HIGH: Unexpected section detected ${sec}.`);
  }
});


// Rule 6: Validate recommended_fixes structure
const recSectionMatch = text.match(/--recommanded_fixes--([\s\S]*?)--final_assessment--/);
if (recSectionMatch) {
  const recText = recSectionMatch[1];

  const requiredGroups = ["CRITICAL", "HIGH", "MEDIUM", "LOW"];
  requiredGroups.forEach(group => {
    if (!recText.includes(group)) {
      isValid = false;
      issues.push(`CRITICAL: Missing ${group} group in recommended_fixes.`);
    }
  });

  if (!/\d+\./.test(recText)) {
    isValid = false;
    issues.push("HIGH: recommended_fixes must contain numbered items.");
  }
} else {
  isValid = false;
  issues.push("CRITICAL: recommended_fixes section structure invalid.");
}

// Rule 7: Empty sections must contain fallback sentence
sections.forEach(section => {
  const regex = new RegExp(`${section}([\\s\\S]*?)(?=--|$)`);
  const match = text.match(regex);

  if (match) {
    const content = match[1].trim();
    if (content === "") {
      isValid = false;
      issues.push(`MEDIUM: ${section} is empty without fallback sentence.`);
    }
  }
});

// Final result
return [{
  json: {
    valid: isValid,
    result: isValid ? "true" : "false",
    issues: isValid ? [] : issues
  }
}];

// ── 1. CONFIGURATION ─────────────────────────────────────────────────────────
const inputUrl  = $('Edit Fields').first().json.URL;
const maxPages  = $input.first().json.maxPages  || 50;
const delayMs   = $input.first().json.delayMs   || 800;
const UA        = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36';

// ── 2. URL HELPERS ────────────────────────────────────────────────────────────
const getOrigin   = url => (url.match(/^(https?:\/\/[^/?#]+)/i) || [])[1] || '';
const getHostname = url => (url.match(/^https?:\/\/([^/?#:]+)/i) || [])[1]?.toLowerCase() || '';
const getPathname = url => (url.replace(/^https?:\/\/[^/?#]+/i, '').match(/^([^?#]*)/) || [])[1] || '/';

function resolveUrl(href, base) {
  if (/^https?:\/\//i.test(href)) return href;
  if (href.startsWith('//'))      return (base.match(/^(https?):/i) || ['','https'])[1] + ':' + href;
  if (href.startsWith('/'))       return getOrigin(base) + href;
  return base.replace(/\?.*/, '').replace(/#.*/, '').replace(/[^/]*$/, '') + href;
}

const sleep = ms => new Promise(r => setTimeout(r, ms));


async function fetchHtml(url) {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: {
      'User-Agent': UA,
      'Accept': 'text/html,application/xhtml+xml,*/*;q=0.9',
    },
    timeout: 20000,
  });
  return res;
}
async function fetchJson(url, extraHeaders = {}) {
  try {
    return await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: {
        'User-Agent': UA,
        'Accept': 'application/json',
        ...extraHeaders,
      },
      timeout: 15000,
      json: true,
    });
  } catch {
    return null;
  }
}
async function fetchGraphQL(endpoint, query, variables = {}) {
  try {
    return await this.helpers.httpRequest({
      method: 'POST',
      url: endpoint,
      body: { query, variables },
      json: true,
    });
  } catch {
    return null;
  }
}

// ── 4. SPA STATE EXTRACTORS ───────────────────────────────────────────────────

/**
 * Extracts every known hydration/SSR state pattern from the raw HTML.
 * Returns an object with all discovered payloads.
 */
function extractInlineState(html) {
  const found = {};

  const patterns = [
    // Next.js
    { key: '__NEXT_DATA__',        re: /<script[^>]+id=["']__NEXT_DATA__["'][^>]*>({.+?})<\/script>/si },
    // Nuxt.js
    { key: '__NUXT__',             re: /window\.__NUXT__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    // Remix / React Router
    { key: '__remixContext',       re: /window\.__remixContext\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    // Generic SSR state bags
    { key: '__INITIAL_STATE__',    re: /window\.__INITIAL_STATE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    { key: '__REDUX_STATE__',      re: /window\.__REDUX_STATE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    { key: '__APP_STATE__',        re: /window\.__APP_STATE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    { key: '__PRELOADED_STATE__',  re: /window\.__PRELOADED_STATE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    { key: '__STORE__',            re: /window\.__STORE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    { key: '__DATA__',             re: /window\.__DATA__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    // Vue / Vite SSR
    { key: '__vue_ssr_context__',  re: /window\.__vue_ssr_context__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    // Svelte Kit
    { key: '__sveltekit_data',     re: /<script[^>]+id=["']__sveltekit_data["'][^>]*>(.+?)<\/script>/si },
    // Angular Transfer State
    { key: 'ng_transfer_state',    re: /<script[^>]+id=["']ng-state["'][^>]*>(.+?)<\/script>/si },
    // Relay / Apollo
    { key: 'relay_data',           re: /window\.__RELAY_STORE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    { key: 'apollo_state',         re: /window\.__APOLLO_STATE__\s*=\s*(\{.+?\})(?:;|\s*<)/si },
    // Generic JSON in <script type="application/json">
    { key: 'json_scripts',         re: /<script[^>]+type=["']application\/json["'][^>]*>(.+?)<\/script>/gsi },
    // Astro
    { key: 'astro_data',           re: /<!--\s*astro-data\s*-->(.+?)<!--\s*\/astro-data\s*-->/si },
  ];

  for (const { key, re } of patterns) {
    if (key === 'json_scripts') {
      // Collect all matches
      const matches = [...html.matchAll(re)].map(m => {
        try { return JSON.parse(m[1].trim()); } catch { return null; }
      }).filter(Boolean);
      if (matches.length) found[key] = matches;
    } else {
      const m = html.match(re);
      if (m) {
        try { found[key] = JSON.parse(m[1].trim()); } catch { found[key + '_raw'] = m[1].trim().slice(0, 500); }
      }
    }
  }

  return found;
}

/**
 * Scans HTML + JS bundles for API base URLs, REST endpoints, and GraphQL endpoints.
 */
function discoverApiEndpoints(html, baseUrl) {
  const origin   = getOrigin(baseUrl);
  const endpoints = { rest: new Set(), graphql: new Set(), apiBase: null };

  // ── A. API base / env vars embedded in HTML
  const basePatterns = [
    /["']?(?:NEXT_PUBLIC_API_URL|VITE_API_URL|REACT_APP_API_URL|VUE_APP_API_URL|API_BASE_URL|API_URL)["']?\s*[:=]\s*["']([^"']+)["']/gi,
    /apiBase(?:Url|URL)?\s*[:=]\s*["']([^"']+)["']/gi,
    /baseURL\s*[:=]\s*["']([^"']+)["']/gi,
  ];
  for (const re of basePatterns) {
    let m;
    while ((m = re.exec(html)) !== null) {
      try { endpoints.apiBase = new URL(m[1], baseUrl).href; break; } catch {}
    }
    if (endpoints.apiBase) break;
  }

  // ── B. Explicit REST paths in the page HTML/JS
  const restRe = /["'`](\/(?:api|v\d|rest|graphql|gql|data|catalog|products?|parts?|items?|inventory|search|list)[^\s"'`]*?)["'`]/gi;
  let rm;
  while ((rm = restRe.exec(html)) !== null) {
    const path = rm[1];
    if (!/\.(js|css|png|svg|jpg|woff)$/.test(path)) {
      endpoints.rest.add(resolveUrl(path, origin + '/'));
    }
  }

  // ── C. GraphQL endpoints
  const gqlRe = /["'`](\/(?:graphql|gql|api\/graphql|query)[^\s"'`]*)["'`]/gi;
  let gm;
  while ((gm = gqlRe.exec(html)) !== null) {
    endpoints.graphql.add(resolveUrl(gm[1], origin + '/'));
  }

  return {
    apiBase:  endpoints.apiBase,
    rest:     [...endpoints.rest],
    graphql:  [...endpoints.graphql],
  };
}

/**
 * Extracts src of all <script> tags (JS bundles to probe).
 */
function extractScriptSrcs(html, baseUrl) {
  const srcs = [];
  const re   = /<script[^>]+src=["']([^"']+)["']/gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    const abs = resolveUrl(m[1], baseUrl);
    if (getHostname(abs) === getHostname(baseUrl)) srcs.push(abs);
  }
  return srcs;
}

// ── 5. PARTS / CATALOG DATA HUNTER ───────────────────────────────────────────

/**
 * Given discovered API info + inline state, tries every reasonable endpoint
 * to pull catalog / parts data with full pagination.
 */
async function huntCatalogData(html, inlineState, apiInfo, baseUrl) {
  const origin   = getOrigin(baseUrl);
  const allItems = [];
  const tried    = new Set();

  // ── A. Pull from inline state first (free, no extra requests)
  function collectFromObj(obj, depth = 0) {
    if (!obj || typeof obj !== 'object' || depth > 8) return;
    for (const [key, val] of Object.entries(obj)) {
      const lk = key.toLowerCase();
      if (Array.isArray(val) && val.length && typeof val[0] === 'object') {
        const looksLikeItems = val.some(v =>
          v && (v.id || v.sku || v.partNumber || v.part_number ||
                v.name || v.title || v.price || v.slug)
        );
        if (looksLikeItems) {
          allItems.push(...val.map(v => ({ _source: `inline:${key}`, ...v })));
        }
      }
      if (typeof val === 'object' && !Array.isArray(val)) collectFromObj(val, depth + 1);
    }
  }
  for (const v of Object.values(inlineState)) collectFromObj(v);

  // ── B. Probe REST endpoints with pagination
  const apiBase = apiInfo.apiBase || origin;

  const candidatePaths = [
    // Parts / catalog specific
    '/api/parts', '/api/parts/list', '/api/parts/search',
    '/api/catalog', '/api/catalog/parts', '/api/catalog/items',
    '/api/products', '/api/products/list', '/api/products/search',
    '/api/items', '/api/inventory', '/api/stock',
    // Versioned
    '/api/v1/parts', '/api/v1/products', '/api/v1/catalog',
    '/api/v2/parts', '/api/v2/products', '/api/v2/catalog',
    '/v1/parts', '/v2/parts', '/v1/products',
    // OEM / automotive parts patterns
    '/api/oem/parts', '/api/fitment', '/api/assemblies',
    // Generic discovery from scanned page
    ...apiInfo.rest.map(u => {
      try { return new URL(u).pathname; } catch { return null; }
    }).filter(Boolean),
  ];

  for (const path of [...new Set(candidatePaths)]) {
    if (allItems.length >= 5000) break; // safety cap

    const endpoint = `${apiBase}${path}`;
    if (tried.has(endpoint)) continue;
    tried.add(endpoint);

    // Page through results
    let page   = 1;
    let hasMore = true;

    while (hasMore && page <= maxPages) {
      await sleep(delayMs);

      // Try multiple pagination param conventions
      const pagingVariants = [
        `${endpoint}?page=${page}&limit=100&per_page=100`,
        `${endpoint}?page=${page}&pageSize=100`,
        `${endpoint}?offset=${(page - 1) * 100}&limit=100`,
        `${endpoint}?skip=${(page - 1) * 100}&take=100`,
      ];

      let data = null;
      for (const pUrl of (page === 1 ? pagingVariants : [pagingVariants[0]])) {
        data = await fetchJson(pUrl);
        if (data) break;
      }

      if (!data) { hasMore = false; break; }

      // Normalize response shape → find the items array
      const items = extractItemsArray(data);
      if (!items || items.length === 0) { hasMore = false; break; }

      allItems.push(...items.map(i => ({ _source: `rest:${path}:p${page}`, ...i })));

      // Detect pagination end
      const total      = data.total ?? data.totalCount ?? data.count ?? data.total_count ?? null;
      const totalPages = data.totalPages ?? data.total_pages ?? data.pages ?? null;
      if      (totalPages && page >= totalPages)           hasMore = false;
      else if (total      && allItems.length >= total)     hasMore = false;
      else if (items.length < 10)                          hasMore = false;
      else                                                 page++;
    }
  }

  // ── C. Try GraphQL introspection + generic parts query
  for (const gqlEndpoint of apiInfo.graphql) {
    if (allItems.length >= 5000) break;

    const introspect = await fetchGraphQL(gqlEndpoint, `{ __schema { queryType { fields { name } } } }`);
    const fields     = introspect?.data?.__schema?.queryType?.fields?.map(f => f.name) || [];
    const partsField = fields.find(f => /part|product|catalog|item|inventory/i.test(f));

    if (partsField) {
      await sleep(delayMs);
      const gqlData = await fetchGraphQL(gqlEndpoint,
        `query GetItems($page: Int) {
          ${partsField}(page: $page, limit: 100, first: 100, perPage: 100) {
            nodes { id sku partNumber name description price stockQty category brand }
            edges { node { id sku partNumber name description price } }
            items { id sku partNumber name description price }
            data  { id sku partNumber name description price }
            total totalCount pageInfo { hasNextPage endCursor }
          }
        }`, { page: 1 }
      );

      const gqlItems = extractItemsArray(gqlData?.data?.[partsField]);
      if (gqlItems?.length) {
        allItems.push(...gqlItems.map(i => ({ _source: `graphql:${partsField}`, ...i })));
      }
    }
  }

  return allItems;
}

/**
 * Walks a response object to find the most-items-like array.
 */
function extractItemsArray(data) {
  if (!data) return [];
  if (Array.isArray(data)) return data;

  const candidates = [
    data.data, data.items, data.results, data.products, data.parts,
    data.catalog, data.list, data.entries, data.records, data.nodes,
    data.edges?.map(e => e.node ?? e),
    data.content, data.payload, data.body,
  ].filter(v => Array.isArray(v) && v.length);

  if (candidates.length === 0) {
    // Try one level deeper
    for (const val of Object.values(data)) {
      if (typeof val === 'object') {
        const sub = extractItemsArray(val);
        if (sub.length) return sub;
      }
    }
    return [];
  }

  return candidates.sort((a, b) => b.length - a.length)[0];
}

// ── 6. MAIN ───────────────────────────────────────────────────────────────────

async function scrapeSpa(startUrl) {
  const errors = [];

  // Step 1 — fetch raw HTML shell
  let html = '';
  try { html = await fetchHtml(startUrl); }
  catch (e) { errors.push({ step: 'fetchHtml', error: e.message }); }

  // Step 2 — extract every inline hydration state blob
  const inlineState = extractInlineState(html);

  // Step 3 — discover API surface from HTML
  const apiInfo = discoverApiEndpoints(html, startUrl);

  // Step 4 — optionally probe the largest JS bundle for more clues
  const scriptSrcs = extractScriptSrcs(html, startUrl);
  if (scriptSrcs.length && !apiInfo.apiBase) {
    // Probe the last/largest bundle (often the main app chunk)
    const bundleUrl = scriptSrcs[scriptSrcs.length - 1];
    try {
      const bundleJs  = await fetchHtml(bundleUrl);
      const bundleApi = discoverApiEndpoints(bundleJs, startUrl);
      if (bundleApi.apiBase && !apiInfo.apiBase) apiInfo.apiBase = bundleApi.apiBase;
      bundleApi.rest.forEach(u => apiInfo.rest.push(u));
      bundleApi.graphql.forEach(u => apiInfo.graphql.push(u));
    } catch (e) {
      errors.push({ step: 'bundleProbe', url: bundleUrl, error: e.message });
    }
  }

  // Step 5 — hunt all parts / catalog items
  let items = [];
  try { items = await huntCatalogData(html, inlineState, apiInfo, startUrl); }
  catch (e) { errors.push({ step: 'huntCatalog', error: e.message }); }

  // Deduplicate by id / sku / partNumber if present
  const seen   = new Set();
  const unique = items.filter(item => {
    const key = item.id ?? item.sku ?? item.partNumber ?? item.part_number ?? JSON.stringify(item);
    if (seen.has(key)) return false;
    seen.add(key); return true;
  });

  return {
    sourceUrl:    startUrl,
    scrapedAt:    new Date().toISOString(),
    totalItems:   unique.length,
    apiDiscovered: {
      apiBase:       apiInfo.apiBase,
      restEndpoints: [...new Set(apiInfo.rest)],
      gqlEndpoints:  [...new Set(apiInfo.graphql)],
    },
    inlineStateKeys: Object.keys(inlineState),
    errors,
    items: unique,
  };
}

// ── 7. EXECUTE & RETURN ───────────────────────────────────────────────────────

const result = await scrapeSpa(inputUrl);

return [
  {
    json: {
      _type:            'summary',
      sourceUrl:        result.sourceUrl,
      scrapedAt:        result.scrapedAt,
      totalItems:       result.totalItems,
      apiDiscovered:    result.apiDiscovered,
      inlineStateKeys:  result.inlineStateKeys,
      errors:           result.errors,
    },
  },
  ...result.items.map((item, index) => ({
    json: {
      _type:     'part',
      index,
      sourceUrl: result.sourceUrl,
      scrapedAt: result.scrapedAt,
      ...item,
    },
  })),
];

// ✅ Safe base URL
const baseUrlRaw = $('Edit Fields').first().json.URL || '';
const baseUrl = baseUrlRaw.replace(/\/$/, '');

// ✅ Get endpoints
let endpoints = $input.first().json.apiDiscovered?.restEndpoints || [];

// Normalize
if (typeof endpoints === 'object' && !Array.isArray(endpoints)) {
  endpoints = Object.values(endpoints);
}
if (typeof endpoints === 'string') {
  endpoints = endpoints.split(/\r?\n/);
}

// Helper to extract path without using URL()
function extractPath(url) {
  try {
    return url.replace(/^https?:\/\/[^/]+/i, '');
  } catch (e) {
    return null;
  }
}

const productPatterns = [];
const realProducts = [];

for (const endpoint of endpoints) {
  if (!endpoint || typeof endpoint !== 'string') continue;

  if (/\/product|\/products/i.test(endpoint)) {

    const path = extractPath(endpoint);
    if (!path) continue;

    // Dynamic routes
    if (endpoint.includes('${') || endpoint.includes(':id')) {

      const normalized = path
        .replace(/\$\{.*?\}/g, '{id}')
        .replace(/:id/g, '{id}');

      productPatterns.push(baseUrl + normalized);

    } else {
      // Static endpoints
      realProducts.push(baseUrl + path);
    }
  }
}

// Remove duplicates
const uniquePatterns = [...new Set(productPatterns)];
const uniqueReal = [...new Set(realProducts)];

// Always return something (debug-friendly)
if (!uniquePatterns.length && !uniqueReal.length) {
  return [{
    json: {
      error: "No product endpoints found",
      endpoints_sample: endpoints.slice(0, 5)
    }
  }];
}

// Output
return [
  ...uniquePatterns.map(p => ({ json: { type: 'pattern', url: p } })),
  ...uniqueReal.map(p => ({ json: { type: 'endpoint', url: p } }))
];

const inputUrl = $('Code in JavaScript3').first().json.url;

// ── 1. Parse frontend base URL + product segment ──────────────────────────────
const protocolEnd = inputUrl.indexOf('://') + 3;
const afterProtocol = inputUrl.slice(protocolEnd);
const slashIdx = afterProtocol.indexOf('/');
const hostname = afterProtocol.slice(0, slashIdx);
const fullPath = afterProtocol.slice(slashIdx);
const protocol = inputUrl.slice(0, protocolEnd - 3);

const frontendBase = `${protocol}://${hostname}`;
const pathParts = fullPath.split('/').filter(p => Boolean(p) && !p.startsWith('{'));
const productSegment = '/' + pathParts.join('/');

// ── 2. HTTP helper ────────────────────────────────────────────────────────────
async function get(url, json = true) {
  try {
    return await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { Accept: json ? 'application/json' : 'text/html,*/*' },
      returnFullResponse: false,
    });
  } catch {
    return null;
  }
}
const GET = get.bind(this);

// ── 3. Fetch homepage HTML → extract all <script src="..."> URLs ──────────────
let html = '';
try {
  html = await this.helpers.httpRequest({
    method: 'GET',
    url: frontendBase,
    headers: { Accept: 'text/html' },
    returnFullResponse: false,
  });
} catch (e) {
  return [{ json: { error: `Could not load homepage: ${e.message}` } }];
}

// Extract script src URLs from HTML
const scriptUrls = [];
const scriptRe = /<script[^>]+src=["']([^"']+)["']/gi;
let m;
while ((m = scriptRe.exec(html)) !== null) {
  const src = m[1];
  const full = src.startsWith('http') ? src : `${frontendBase}${src.startsWith('/') ? '' : '/'}${src}`;
  scriptUrls.push(full);
}

// ── 4. Scan JS bundles for API URL patterns ───────────────────────────────────
const apiCandidates = new Set();

// Patterns that look like API base URLs or product endpoints in JS source
const urlPatterns = [
  // full https URLs containing api-like paths
  /https?:\/\/[a-zA-Z0-9._\-]+(?:\.com|\.app|\.io|\.dev|\.net)(\/[a-zA-Z0-9/_\-]*)?/g,
];

for (const scriptUrl of scriptUrls) {
  let js = null;
  try {
    js = await this.helpers.httpRequest({
      method: 'GET',
      url: scriptUrl,
      returnFullResponse: false,
    });
  } catch { continue; }

  if (typeof js !== 'string') continue;

  // Find all URLs embedded in the JS
  const found = js.match(/https?:\/\/[a-zA-Z0-9._\-]+(\.com|\.app|\.io|\.dev|\.net)(\/[^\s"'`\\,)};]+)?/g) || [];
  for (const u of found) {
    // Only keep URLs that look like API base URLs (not images, fonts, analytics etc.)
    if (/\.(png|jpg|jpeg|gif|svg|woff|woff2|ttf|css|ico)$/i.test(u)) continue;
    if (/google|facebook|twitter|analytics|gtm|hotjar|sentry|cdn\.|fonts\./i.test(u)) continue;
    apiCandidates.add(u.replace(/\/$/, '')); // strip trailing slash
  }
}

// ── 5. Try each discovered URL as a products endpoint ────────────────────────
let products = [];
let workingApi = null;

// Also always try common suffixes on every candidate base
const suffixes = ['', '/products', '/api/products', '/items', '/api/items', '/catalog'];

const toTry = [];
for (const candidate of apiCandidates) {
  for (const suffix of suffixes) {
    toTry.push(candidate + suffix);
  }
}

// Deduplicate
const seen = new Set();
const uniqueToTry = toTry.filter(u => { if (seen.has(u)) return false; seen.add(u); return true; });

for (const endpoint of uniqueToTry) {
  let data = await GET(endpoint);
  if (!data) continue;

  const items = Array.isArray(data)
    ? data
    : data.products || data.items || data.data || data.results || null;

  if (!Array.isArray(items) || items.length === 0) continue;

  // Confirm items look like products (have id + at least one of: title/name/price)
  const looksLikeProducts = items.every(p =>
    (p.id !== undefined || p._id !== undefined || p.slug !== undefined) &&
    (p.title !== undefined || p.name !== undefined || p.price !== undefined)
  );

  if (looksLikeProducts) {
    products = items;
    workingApi = endpoint;
    break;
  }
}

// ── 6. Output ─────────────────────────────────────────────────────────────────
if (products.length === 0) {
  return [{ json: {
    error: 'Could not discover products API',
    frontendBase,
    productSegment,
    scannedScripts: scriptUrls.length,
    candidatesFound: apiCandidates.size,
    candidates: [...apiCandidates].slice(0, 20),
  }}];
}

const productUrls = products.map(p => {
  const id = p.id ?? p._id ?? p.slug ?? p.handle ?? p.productId;
  return `${frontendBase}${productSegment}/${id}`;
});

return productUrls.map((url, i) => ({
  json: {
    index:      i + 1,
    url,
    title:      products[i].title ?? products[i].name ?? '',
    price:      products[i].price ?? '',
    category:   products[i].category ?? '',
    api_used:   workingApi,
    all_urls:   productUrls.join('\n')
  }
}));

const pageUrl = $input.first().json.url;

// ✅ FIX: extract ONLY origin (not path)
const origin = pageUrl.match(/^https?:\/\/[^/]+/i)?.[0];

if (!origin) {
  return [{
    json: { error: "Invalid URL" }
  }];
}

// common product endpoints
const possibleApis = [
  '/products',
  '/api/products',
  '/api/v1/products',
  '/v1/products',
  '/catalog',
  '/api/catalog'
];

return possibleApis.map(p => ({
  json: {
    url: origin + p
  }
}));

